import axios from 'axios';

// Create axios instance with custom config
const apiClient = axios.create({
  baseURL: 'http://127.0.0.1:8000',  // Use IP address instead of localhost
  timeout: 60000, // 60 seconds
  headers: {
    'Content-Type': 'application/json',
  }
});

// File system operations
export const uploadFile = async (file, path = '') => {
  try {
    console.log(`Starting upload for file: ${file.name} (size: ${file.size} bytes)`);
    const formData = new FormData();
    formData.append('file', file);
    formData.append('path', path);

    // Log the request details
    console.log('Upload request:', {
      url: 'http://127.0.0.1:8000/api/upload',
      method: 'POST',
      headers: {
        'Content-Type': 'multipart/form-data'
      },
      data: {
        file: file.name,
        path: path
      }
    });

    const response = await axios({
      method: 'post',
      url: 'http://127.0.0.1:8000/api/upload',
      data: formData,
      headers: {
        'Content-Type': 'multipart/form-data',
        'Accept': 'application/json'
      },
      withCredentials: false,
      maxContentLength: Infinity,
      maxBodyLength: Infinity,
      onUploadProgress: (progressEvent) => {
        const percentCompleted = Math.round((progressEvent.loaded * 100) / progressEvent.total);
        console.log(`Upload progress for ${file.name}: ${percentCompleted}%`);
      },
    });

    console.log(`Upload successful for ${file.name}:`, response.data);
    return response.data;
  } catch (error) {
    console.error('Upload error details:', {
      error: error.message,
      response: error.response?.data,
      request: error.request ? 'Request was made but no response' : 'Request setup failed',
      config: error.config,
      status: error.response?.status,
      statusText: error.response?.statusText
    });

    if (error.response) {
      throw new Error(`Server error (${error.response.status}): ${error.response.data?.error || error.response.statusText}`);
    } else if (error.request) {
      throw new Error('Network error: Cannot connect to server. Please check if the server is running.');
    } else {
      throw new Error(`Request failed: ${error.message}`);
    }
  }
};

export const uploadFiles = async (files, path = '') => {
  console.log(`Starting upload of ${files.length} files to path: ${path}`);
  const results = {
    successful: [],
    failed: [],
  };

  // Upload files sequentially
  for (const file of files) {
    try {
      console.log(`Processing file: ${file.name}`);
      const result = await uploadFile(file, path);
      console.log(`Successfully uploaded ${file.name}`);
      results.successful.push({ file: file.name, result });
    } catch (error) {
      console.error(`Failed to upload ${file.name}:`, error);
      results.failed.push({ 
        file: file.name, 
        error: error.message || 'Unknown error occurred'
      });
    }
  }

  console.log('Upload results:', results);
  return results;
};

// Other API functions
export const listFiles = async (path = '') => {
  try {
    const response = await apiClient.get('/api/files', { params: { path } });
    return response.data.files || [];
  } catch (error) {
    console.error('List files error:', error);
    return [];
  }
};

export const readFile = async (path) => {
  try {
    const response = await apiClient.get('/api/files/read', { params: { path } });
    return response.data.content;
  } catch (error) {
    throw error;
  }
};

export const deletePath = async (path) => {
  try {
    console.log(`Deleting path: ${path}`);
    const response = await axios({
      method: 'delete',
      url: 'http://127.0.0.1:8000/api/files',
      params: { path },
      headers: {
        'Accept': 'application/json'
      },
      withCredentials: false
    });
    console.log('Delete response:', response.data);
    return response.data;
  } catch (error) {
    console.error('Delete error details:', {
      error: error.message,
      response: error.response?.data,
      request: error.request ? 'Request was made but no response' : 'Request setup failed',
      config: error.config,
      status: error.response?.status,
      statusText: error.response?.statusText
    });

    if (error.response) {
      throw new Error(`Server error (${error.response.status}): ${error.response.data?.error || error.response.statusText}`);
    } else if (error.request) {
      throw new Error('Network error: Cannot connect to server. Please check if the server is running.');
    } else {
      throw new Error(`Request failed: ${error.message}`);
    }
  }
};

export const searchFiles = async (query) => {
  try {
    const response = await apiClient.get('/api/files/search', { params: { query } });
    return response.data.results || [];
  } catch (error) {
    return [];
  }
};

// AI-related functions (currently disabled)
export const chat = async (messages) => {
  throw new Error('Chat functionality is currently disabled');
};

export const analyzeCode = async (code) => {
  throw new Error('Code analysis functionality is currently disabled');
};

export const generateCode = async (prompt) => {
  throw new Error('Code generation functionality is currently disabled');
};

export default apiClient;
